import{_ as i,o,c as t,ag as a}from"./chunks/framework.CMYkYJvz.js";const h=JSON.parse('{"title":"Project Overview","description":"Understand Bifrost positioning, scope, and common use cases.","frontmatter":{"title":"Project Overview","description":"Understand Bifrost positioning, scope, and common use cases.","editLink":false},"headers":[],"relativePath":"en/getting-started/overview.md","filePath":"en/getting-started/overview.md"}'),r={name:"en/getting-started/overview.md"};function n(s,e,l,d,c,u){return o(),t("div",null,[...e[0]||(e[0]=[a('<blockquote><p>This page is automatically synced from <code>docs-en/overview.md</code>. Language: <strong>English</strong> | <a href="./../../getting-started/overview">中文</a></p></blockquote><h1 id="what-is-bifrost" tabindex="-1">What Is Bifrost <a class="header-anchor" href="#what-is-bifrost" aria-label="Permalink to &quot;What Is Bifrost&quot;">​</a></h1><p>Bifrost is a high-performance proxy server written in Rust. It is inspired by Whistle, but its goal is broader than forwarding requests: it combines rules, scripting, traffic observability, TLS MITM, replay, and a Web UI into one workflow.</p><h2 id="who-should-use-it" tabindex="-1">Who Should Use It <a class="header-anchor" href="#who-should-use-it" aria-label="Permalink to &quot;Who Should Use It&quot;">​</a></h2><ul><li>Frontend and backend engineers who need a local proxy for API debugging.</li><li>QA engineers who need to capture traffic, rewrite requests, and verify edge cases.</li><li>Advanced users who need custom scripts and complex rule orchestration.</li><li>Teams that need a desktop-friendly workflow for network debugging and protocol inspection.</li></ul><h2 id="core-capabilities" tabindex="-1">Core Capabilities <a class="header-anchor" href="#core-capabilities" aria-label="Permalink to &quot;Core Capabilities&quot;">​</a></h2><ul><li>HTTP/1.1, HTTP/2, HTTP/3, HTTPS, SOCKS5, WebSocket, and SSE support.</li><li>TLS MITM, CA management, and domain-level intercept or passthrough control.</li><li>Rich Rules syntax for rewrite, routing, mock responses, injection, delay, and throttling.</li><li>QuickJS-based sandbox scripting for dynamic logic.</li><li>Built-in Web UI for traffic inspection, rule editing, request replay, and script logs.</li><li>Temporary port bindings so one long-running Bifrost service can isolate multiple tasks by entry port.</li><li>Remote invoke for authorized remote traffic queries, remote file access, and policy-bound shell commands.</li><li>Agent Skill installation so coding agents can use real traffic evidence for automation.</li></ul><h2 id="product-forms" tabindex="-1">Product Forms <a class="header-anchor" href="#product-forms" aria-label="Permalink to &quot;Product Forms&quot;">​</a></h2><ul><li><code>CLI</code>: service deployment, scripting, and automation.</li><li><code>Desktop</code>: daily local proxy debugging.</li><li><code>Web UI</code>: visual traffic inspection and rule management.</li></ul>',9)])])}const f=i(r,[["render",n]]);export{h as __pageData,f as default};
